import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input from a form field
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Sanitize and escape user input before outputting it to an HTML page
        HTMLEntityCodec codec = new HTMLEntityCodec();
        String safeUserInput = codec.encodeForHTML(userInput);

        // Output the HTML content containing the sanitized user input
        String outputHtml = "<html><body><p>" + safeUserInput + "</p></body></html>";

        // Output the sanitized HTML content
        System.out.println(outputHtml);
    }
}

